window.DESC = {
  hypothalamus:{cat:'CNS/Behavioral',desc:'Master energy homeostasis integrator. Receives: leptin (↑ satiety), ghrelin (↑ hunger), CCK/PYY (satiety), glucose, insulin. Two opposing neuron populations: orexigenic NPY/AgRP and anorexigenic POMC/CART. Also drives stress axis (CRH) and sympathetic NS.'},
  npy_agrp:{cat:'CNS/Behavioral',desc:'Orexigenic neurons. NPY = neuropeptide Y; AgRP = agouti-related peptide (MC4R inverse agonist). Stimulated by ghrelin; inhibited by leptin and insulin. Drive food-seeking behavior. Fasting markedly increases NPY/AgRP activity.'},
  pomc_cart:{cat:'CNS/Behavioral',desc:'Anorexigenic neurons. POMC → α-MSH → activates MC4R → ↓ appetite. CART suppresses feeding. Activated by leptin; inhibited by ghrelin. Target of leptin signaling in obesity.'},
  ghrelin_beh:{cat:'CNS/Behavioral',desc:'Orexigenic peptide from gastric fundus. The only known circulating hunger hormone. Rises pre-meal, falls post-meal. Activates NPY/AgRP. Also stimulates GH release from anterior pituitary.'},
  leptin_beh:{cat:'CNS/Behavioral',desc:'Adipokine proportional to fat mass. Signals satiety to hypothalamus — activates POMC/CART, inhibits NPY/AgRP. Leptin resistance (not leptin deficiency) causes common obesity. Also activates AMPK peripherally.'},
  cck_beh:{cat:'CNS/Behavioral',desc:'CCK from I-cells of SI. Fat+protein → CCK release. Satiety via vagal afferents to hypothalamus. Also acts locally (↑ pancreatic enzymes, GB contraction). Short-term satiety signal.'},
  pyy_beh:{cat:'CNS/Behavioral',desc:'PYY from L-cells of ileum/colon. Released proportional to calories. Acts on hypothalamus to suppress appetite. Works with GLP-1 for post-meal satiety. Important bariatric surgery mechanism.'},
  crh:{cat:'Stress Axis',desc:'Corticotropin-releasing hormone from hypothalamic PVN. Released under stress → anterior pituitary → ACTH → cortisol. CRH also activates sympathetic NS directly.'},
  anterior_pit:{cat:'Stress Axis',desc:'Secretes ACTH in response to CRH. ACTH travels via blood to adrenal cortex → stimulates cortisol synthesis (cAMP-PKA pathway).'},
  acth:{cat:'Stress Axis',desc:'Adrenocorticotropic hormone. Binds MC2R on adrenal zona fasciculata → cortisol synthesis. Part of the HPA (hypothalamic-pituitary-adrenal) axis.'},
  adrenal_cortex:{cat:'Stress Axis',desc:'Zona fasciculata responds to ACTH → cortisol (glucocorticoid). Zona glomerulosa → aldosterone (Na+/K+ regulation). Steroid hormones derived from cholesterol.'},
  adrenal_medulla:{cat:'Stress Axis',desc:'Modified sympathetic ganglion. Releases epinephrine (80%) + norepinephrine (20%) → rapid fight-or-flight metabolic mobilization: ↑ glycogenolysis, ↑ lipolysis, ↓ insulin.'},
  sympathetic:{cat:'Stress Axis',desc:'Fight-or-flight. Releases NE at synapses + stimulates adrenal medulla. Direct metabolic: ↑ glycogenolysis (liver/muscle), ↑ lipolysis (adipose), ↑ glucagon, ↓ insulin.'},
  mouth:{cat:'GI Tract',desc:'Salivary α-amylase: starch → maltose + dextrins (α-1,4 bonds). Lingual lipase (minor). Chewing = mechanical processing. Amylase inactivated by stomach HCl.'},
  stomach_gi:{cat:'GI Tract',desc:'Chief cells: pepsinogen (activated by HCl → pepsin, cleaves Phe/Tyr). Parietal cells: HCl + intrinsic factor (IF for B12 absorption). G-cells: gastrin → ↑ HCl. Gastric lipase (minor TG digestion).'},
  si_gi:{cat:'GI Tract',desc:'Primary digestion/absorption site. Duodenum: bile + pancreatic enzymes; CCK/secretin released. Jejunum: major absorption. Ileum: B12 (bound to IF), bile acid reabsorption (enterohepatic circulation).'},
  pancreas_enz:{cat:'GI Tract',desc:'Exocrine: amylase (starch), lipase (TG→2-MAG+2FFA), trypsin+chymotrypsin (activated by enterokinase), elastase, carboxypeptidase. Also: HCO3- (neutralizes acid chyme). Stimulated by CCK and secretin.'},
  bile:{cat:'GI Tract',desc:'Bile salts (cholesterol-derived, liver-made, gallbladder-stored). Amphipathic → emulsify dietary fats → micelles. CCK triggers GB contraction. Bile salts recycled via enterohepatic circulation (ileal reabsorption).'},
  brush_border:{cat:'GI Tract',desc:'Enterocyte apical membrane enzymes: maltase (maltose→2 glucose), sucrase (sucrose→glucose+fructose), lactase (lactose→glucose+galactose), aminopeptidases. Lactase deficiency = lactose intolerance.'},
  micelles:{cat:'GI Tract',desc:'Mixed micelles: bile salts + FA + 2-MAG + fat-soluble vitamins (A,D,E,K). Present lipids to brush border for passive absorption. FAs + 2-MAG diffuse into enterocytes → re-esterified as TG.'},
  absorption:{cat:'GI Tract',desc:'Glucose: SGLT1 (Na-cotransport, apical) → GLUT2 (basolateral). Fructose: GLUT5 (apical). AAs: Na-cotransporters. FAs: passive → TG re-synthesis → chylomicrons (apoB-48) → lacteals → lymph → thoracic duct → blood.'},
  insulin:{cat:'Hormone',desc:'Anabolic peptide from β-cells. Released by: glucose↑, AAs↑, GIP/GLP-1. Receptor: RTK (IRS-1→PI3K→Akt). Effects: ↑GLUT4 (muscle/adipose), ↑glycogen synthase, ↑PFK-1 (via ↑F2,6-BP), ↑ACC (lipogenesis), ↓FBPase-1 (↓GNG), ↓glycogen phosphorylase, ↓HSL (↓lipolysis).'},
  glucagon:{cat:'Hormone',desc:'Catabolic peptide from α-cells. Released by: glucose↓, AAs (Arg). Via cAMP-PKA: ↑glycogen phosphorylase, ↓glycogen synthase, ↑FBPase-1 (via ↓F2,6-BP), ↓PFK-1, ↑PEPCK (↑GNG), ↑lipolysis, ↑ketogenesis. Completely opposes insulin.'},
  cortisol:{cat:'Hormone',desc:'Glucocorticoid steroid (delayed hours via nuclear receptor). ↑ GNG (↑PEPCK gene transcription), ↑ protein catabolism → AAs for GNG, ↑ lipolysis, ↓ glucose uptake in peripheral tissues (anti-insulin). Anti-inflammatory. Permissive for glucagon/epi.'},
  epinephrine:{cat:'Hormone',desc:'Catecholamine from adrenal medulla. Rapid via β-AR (cAMP-PKA): ↑ glycogenolysis (liver+muscle), ↑ HSL → lipolysis, ↑ glucagon, ↓ insulin (α-AR on β-cells). Prepares for fight-or-flight energy mobilization.'},
  leptin:{cat:'Hormone',desc:'Adipokine ∝ fat mass. CNS: activates POMC/CART, inhibits NPY/AgRP. Peripheral: activates AMPK (select tissues), ↑ β-oxidation. Leptin resistance underlies common obesity (hypothalamus unresponsive despite high leptin).'},
  ghrelin:{cat:'Hormone',desc:'"Hunger hormone." From gastric fundus X/A cells. Empty stomach → ghrelin↑ → NPY/AgRP activation. Falls post-meal. Also stimulates GH from anterior pituitary. Opposes leptin at hypothalamus.'},
  cck:{cat:'Hormone',desc:'CCK from I-cells (duodenum/jejunum). Fats+proteins → CCK. Effects: ↑ pancreatic enzyme secretion, GB contraction (bile release), satiety via vagus. Slows gastric emptying. Short-acting satiety.'},
  pyy:{cat:'Hormone',desc:'From L-cells of distal intestine ∝ caloric intake. Inhibits NPY/AgRP in hypothalamus → satiety. Important mechanism by which bariatric surgery (particularly Roux-en-Y) reduces hunger.'},
  somatostatin:{cat:'Hormone',desc:'From δ-cells of pancreas and GI. Inhibits BOTH insulin (β-cells) and glucagon (α-cells). Inhibits GH, TSH. Acts as endocrine pancreas brake. Used therapeutically (octreotide) for acromegaly, carcinoid.'},
  incretins:{cat:'Hormone',desc:'GIP (K-cells) + GLP-1 (L-cells). Released by oral glucose → amplify insulin secretion (the incretin effect: oral > IV glucose for insulin release). GLP-1 also: ↓ glucagon, ↓ gastric emptying, ↑ satiety. GLP-1 agonists (semaglutide) are major T2DM/obesity drugs.'},
  chylomicrons:{cat:'Blood/Transport',desc:'Largest, least dense lipoprotein. Made in enterocytes from dietary TG+cholesterol. ApoB-48. Travel via lacteals → lymph → thoracic duct → blood. LPL degrades → chylomicron remnants taken up by liver (ApoE recognition).'},
  blood_glucose:{cat:'Blood/Extracellular',desc:'Normal fasting: 70-100 mg/dL. GLUT transporters: GLUT1 (RBC, brain, constitutive), GLUT2 (liver/pancreas, high Km = glucose sensor), GLUT3 (brain, high affinity), GLUT4 (muscle/adipose, insulin-dependent). Triggers insulin (↑) or glucagon (↓).'},
  blood_ffa:{cat:'Blood/Extracellular',desc:'Non-esterified FAs bound to albumin. Released by adipose lipolysis (HSL, ATGL). Primary fuel for heart, liver, resting muscle. Cannot cross BBB → brain cannot use FFAs directly. Elevated in T2DM, obesity, starvation.'},
  blood_aa:{cat:'Blood/Extracellular',desc:'From dietary absorption + protein catabolism. Gluconeogenic substrates. Trigger insulin (especially branched-chain AAs) and glucagon (especially Arg). BCAAs (Leu, Ile, Val) metabolized mainly in muscle, not liver.'},
  vldl:{cat:'Blood/Transport',desc:'Very Low Density Lipoprotein. Liver-made from endogenous TG + cholesterol. ApoB-100. Delivers TG to peripheral tissues. Degraded by LPL → IDL → LDL. High VLDL = hypertriglyceridemia. Insulin stimulates VLDL secretion.'},
  lpl:{cat:'Blood/Transport',desc:'Lipoprotein Lipase on capillary walls (muscle, heart, adipose). Cleaves TG from chylomicrons+VLDL → FFA+glycerol for uptake. ApoC-II activates; ApoC-III inhibits. Insulin ↑LPL in adipose. Muscle LPL provides FAs for β-oxidation.'},
  rbc:{cat:'Organ',desc:'No mitochondria → 100% anaerobic glycolysis only. Export lactate (Cori cycle). PPP heavily used: NADPH → glutathione peroxidase → protect against oxidative hemolysis. G6PD deficiency: X-linked, PPP blocked → hemolytic anemia with oxidants (primaquine, fava beans).'},
  liver_organ:{cat:'Organ',desc:'Metabolic HUB. Unique capabilities: gluconeogenesis (has G6Pase), glycogenolysis+glycogenesis (100g glycogen), FA synthesis, β-oxidation, ketogenesis (not ketone use), VLDL secretion, urea cycle, drug metabolism (CYP450), bile synthesis. First-pass portal blood.'},
  muscle_organ:{cat:'Organ',desc:'Largest glucose consumer (GLUT4, insulin-dependent). Has ~400g glycogen (no G6Pase → local use only). Uses glucose, FFAs, ketones. Exports lactate (→ Cori cycle) + alanine (→ glucose-alanine cycle) to liver. At rest: mainly β-oxidation.'},
  brain_organ:{cat:'Organ',desc:'Uses 120g glucose/day normally (GLUT1/3, constitutive). Cannot oxidize FFAs (no β-oxidation). In starvation: adapts to ketones (acetoacetate, β-OHB) → spares protein. Minimum ~30g/day glucose even in ketosis. Extremely sensitive to hypoglycemia.'},
  adipose_organ:{cat:'Organ',desc:'Energy storage. Fed+insulin: GLUT4↑, lipogenesis (glucose→G3P+FFA→TG). Fasting+glucagon/epi/cortisol: HSL+ATGL → lipolysis → FFA+glycerol. Glycerol → liver GNG. FFA → blood. Endocrine: secretes leptin, adiponectin, resistin.'},
  kidney_organ:{cat:'Organ',desc:'GNG in fasting (has all GNG enzymes + G6Pase). Metabolizes glutamine → NH4+ + HCO3- (acid-base regulation). Reabsorbs glucose via SGLT2 (therapeutic target: SGLT2 inhibitors). Activates vitamin D (1-α-hydroxylase).'},
  glycogen:{cat:'Cytoplasm',desc:'Glucose polymer (α-1,4 links, α-1,6 branches every 8-10). Liver: ~100g (blood glucose buffer). Muscle: ~400g (local fuel, no G6Pase). Depleted in ~12-18 hrs fasting. Primer: glycogenin. Branches: branching enzyme (α-1,4→α-1,6), debranching enzyme (glycogenolysis).'},
  glycogen_synthase:{cat:'Cytoplasm',desc:'Active = dephosphorylated. Activators: insulin (→PP1 phosphatase), G6P (allosteric). Inhibitors (phosphorylation): PKA (glucagon, epi), AMPK. Reciprocal regulation with glycogen phosphorylase — cannot be active simultaneously in normal physiology.'},
  glycogen_phosphorylase:{cat:'Cytoplasm',desc:'Active = phosphorylated (phosphorylase a). Activated: AMP (allosteric, low energy), PKA cascade (glucagon, epi), Ca²⁺ (muscle). Inhibited: ATP, G6P (energy sufficient), insulin (via PP1), glucose (liver isoform). Rate-limiting for glycogenolysis.'},
  ppp:{cat:'Cytoplasm',desc:'Pentose Phosphate Pathway (HMP shunt). OXIDATIVE PHASE: G6P → NADPH(×2) + CO2 + ribulose-5-P. Rate-limited by G6PD (product-inhibited by NADPH). NON-OXIDATIVE PHASE: transketolase (B1/thiamine!), transaldolase → F6P, G3P (back to glycolysis), ribose-5-P. HIGH in: RBCs, liver, lactating mammary, adrenals (NADPH for steroid synthesis).'},
  nadph_cyto:{cat:'Cytoplasm',desc:'NADPH (cytoplasmic): (1) FA synthesis — FAS needs 14 NADPH per palmitate, (2) Glutathione reduction (antioxidant, critical in RBCs), (3) P450 detox reactions, (4) Cholesterol synthesis, (5) Steroid hydroxylation. DISTINCT from mitochondrial NADH (ETC). Malic enzyme also produces NADPH (malate→pyruvate).'},
  ribose5p:{cat:'Cytoplasm',desc:'From PPP non-oxidative phase. Required for: nucleotide synthesis (DNA/RNA/ATP/NAD/FAD/CoA). Rapidly dividing cells (bone marrow, GI epithelium) need lots. If NADPH demand > ribose need: non-oxidative phase runs in reverse to convert ribose → F6P/G3P.'},
  glucose_cyto:{cat:'Cytoplasm',desc:'Glycolysis entry. Phosphorylated immediately → G6P (traps glucose). Hexokinase (brain/muscle): low Km, high affinity, inhibited by G6P. Glucokinase (liver/pancreas β-cells): high Km, not inhibited by G6P → acts as glucose sensor. GLUT2 in liver.'},
  g6p:{cat:'Cytoplasm',desc:'Central junction: → glycolysis (PGI → F6P), glycogenesis (PGM → G1P → UDP-glc), PPP (G6PD), or back to glucose via G6Pase (liver/kidney only). G6P: allosterically activates glycogen synthase; inhibits hexokinase (not glucokinase); inhibits glycogen phosphorylase.'},
  f6p:{cat:'Cytoplasm',desc:'Between G6P and the main regulatory step (PFK-1). Also substrate for PFK-2 → F2,6-BP (key regulator of PFK-1). In GNG: produced from F1,6-BP by FBPase-1.'},
  pfk1:{cat:'Cytoplasm',desc:'PFK-1: RATE-LIMITING of glycolysis. IRREVERSIBLE. ✦ Activated by: AMP, ADP, F2,6-BP (strongest!), NH4+. ✗ Inhibited by: ATP (allosteric, sigmoidal kinetics), citrate (TCA saturation signal), H+. F2,6-BP is the dominant acute regulator — controlled by insulin (↑) and glucagon (↓) via PFK-2/FBPase-2.'},
  f16bp:{cat:'Cytoplasm',desc:'Fructose-1,6-bisphosphate. PFK-1 product (glycolysis) / FBPase-1 substrate (GNG). Allosterically activates pyruvate kinase (feed-forward). Split by aldolase → DHAP + G3P. Aldolase reaction is the only C-C bond cleavage in glycolysis.'},
  g3p_dhap:{cat:'Cytoplasm',desc:'G3P (glyceraldehyde-3-phosphate) → continues glycolysis → 2 ATP + 2 NADH per G3P. DHAP ↔ G3P (triose phosphate isomerase, TPI). DHAP → glycerol-3-P (for TG backbone). This is how glycerol from lipolysis enters gluconeogenesis.'},
  pyruvate_cyto:{cat:'Cytoplasm',desc:'Final glycolysis product. FATES: (1) → Mito → PDH → Acetyl-CoA (aerobic); (2) → LDH → Lactate (anaerobic, regenerates NAD+); (3) → Pyruvate carboxylase → OAA (GNG, needs acetyl-CoA activation); (4) → ALT → Alanine (glucose-alanine cycle); (5) → PDH bypass in some pathways.'},
  lactate:{cat:'Cytoplasm',desc:'LDH: pyruvate + NADH → lactate + NAD+. Regenerates NAD+ → allows continued anaerobic glycolysis. Exported to blood → liver (Cori cycle): lactate → pyruvate → GNG → glucose. Also: exercising muscle, RBCs, tumor cells (Warburg effect). Lactic acidosis (pH↓) in severe ischemia, PDH deficiency, metformin overdose.'},
  fbpase1:{cat:'Cytoplasm',desc:'FBPase-1: rate-limiting of GNG. IRREVERSIBLE bypass of PFK-1. ✗ Inhibited by: AMP (low energy → no GNG), F2,6-BP (insulin signal → no GNG). ✦ Activated by: citrate (energy full → ↑ GNG), glucagon (via ↓F2,6-BP). Reciprocally regulated with PFK-1 — when one is on, the other is off. Prevents futile cycling.'},
  pep:{cat:'Cytoplasm',desc:'Phosphoenolpyruvate. High-energy intermediate. In glycolysis: PEP → pyruvate (pyruvate kinase, +ATP). In GNG: OAA → PEP via PEPCK (2nd bypass point). PEP + pyruvate kinase step is also irreversible in glycolysis (3rd GNG bypass).'},
  pepck:{cat:'Cytoplasm',desc:'PEPCK: OAA → PEP + CO2 (uses GTP). 2nd GNG bypass. Induced transcriptionally by: glucagon, cortisol, cAMP. Repressed by insulin. Key rate-limiting enzyme of GNG. Localized in cytoplasm (mammalian).'},
  oaa_cyto:{cat:'Cytoplasm',desc:'Cytoplasmic OAA for GNG. Source: pyruvate carboxylase (mito) → OAA transported out as malate (via malate-aspartate shuttle in reverse) or aspartate → reconverted in cytoplasm. Also from citrate shuttle (ATP-citrate lyase → acetyl-CoA + OAA).'},
  pyruvate_carboxylase:{cat:'Cytoplasm',desc:'Located in mitochondria. Pyruvate + CO2 + ATP → OAA (requires biotin/B7). ALLOSTERICALLY ACTIVATED by acetyl-CoA — this is critical: when FAs are being oxidized (high acetyl-CoA), pyruvate carboxylase ↑ → OAA ↑ → TCA replenished AND GNG fueled. Inhibited when acetyl-CoA is low.'},
  g6pase:{cat:'Cytoplasm',desc:'Located in ER lumen. Present ONLY in liver, kidney, intestine (NOT muscle → muscle glycogen cannot be released to blood). Final step of both GNG and glycogenolysis: G6P → glucose → exported. Deficiency = von Gierke disease (glycogen storage type I).'},
  amp:{cat:'Regulator',desc:'AMP = low energy signal. AMP/ATP ratio rises dramatically when energy is low (AMP changes ~100× more than ATP). ✦ Activates: PFK-1 (↑ glycolysis), AMPK (master catabolic kinase), glycogen phosphorylase (↑ glycogenolysis). ✗ Inhibits: FBPase-1 (↓ GNG). The body is maximally sensitive to this signal.'},
  atp_reg:{cat:'Regulator',desc:'ATP = high energy signal. ✗ Inhibits: PFK-1 (allosteric, high-affinity site changes sigmoidal kinetics), citrate synthase (TCA entry), isocitrate DH (TCA rate-lim.), glycogen phosphorylase (energy sufficient). Signals: slow down catabolism, we have enough fuel.'},
  f26bp:{cat:'Regulator',desc:'F-2,6-bisphosphate: regulatory molecule only (NOT a glycolysis intermediate). Made by PFK-2 domain; broken by FBPase-2 domain of the SAME bifunctional enzyme. Insulin: activates PFK-2 (phosphatase) → ↑F2,6-BP → ↑PFK-1 + ↓FBPase-1. Glucagon: activates FBPase-2 → ↓F2,6-BP → ↓PFK-1 + ↑FBPase-1. MOST POTENT PFK-1 activator.'},
  ampk:{cat:'Regulator',desc:'AMP-Activated Protein Kinase = master energy sensor. Activated by: ↑AMP/ATP ratio (starvation, exercise), leptin, adiponectin, METFORMIN (T2DM drug). When active: ↑β-oxidation (↑CPT-1 activity), ↑glucose uptake, ↑glycolysis. ✗ Inhibits: ACC (→↓malonyl-CoA→↑CPT-1→↑β-oxidation), FA synthesis, glycogen synthesis, GNG. Metformin works through AMPK activation.'},
  citrate_reg:{cat:'Regulator',desc:'Citrate exits mito when TCA is saturated (energy full). In cytoplasm: (1) ✗ Inhibits PFK-1 — "enough acetyl-CoA from TCA, stop glycolysis"; (2) ✦ Activates ACC → malonyl-CoA → FA synthesis; (3) ✦ Activates FBPase-1 → ↑ GNG. Citrate is thus the "energy-replete" signal that switches metabolism from catabolism to anabolic fat storage.'},
  nadh_mito:{cat:'Regulator',desc:'Mitochondrial NADH. High NADH/NAD+ = energy surplus. Product inhibition: ✗ Inhibits PDH, citrate synthase, isocitrate DH, α-KG DH. Slows TCA when already producing enough reducing equivalents. Donates electrons to Complex I.'},
  fadh2:{cat:'Regulator',desc:'FADH2 from: succinate DH (TCA = Complex II) and β-oxidation. Donates electrons to CoQ in Complex II (no H+ pumping → less ATP: ~1.5 ATP vs NADH → ~2.5 ATP). This explains why FAs give more ATP/carbon than glucose (more FADH2 + NADH generated per acetyl-CoA).'},
  aa_catabolism:{cat:'Cytoplasm',desc:'Step 1: Transamination — aminotransferases (ALT, AST) transfer -NH2 to α-KG → glutamate + α-keto acid. Requires PLP (pyridoxal phosphate, B6). Step 2: Oxidative deamination — glutamate → α-KG + NH4+ (GDH, reversible). NH4+ → urea cycle. α-Keto acids → various TCA entry points.'},
  glutamate:{cat:'Cytoplasm',desc:'Hub of nitrogen metabolism. Accepts amino groups in transamination (becomes glutamate from α-KG). GDH: glutamate ↔ α-KG + NH4+ (reversible). NAD+ or NADP+ dependent. NH4+ → urea cycle. Glutamate also → GABA (CNS), glutamine (N carrier), aspartate (urea cycle N donor).'},
  alanine:{cat:'Cytoplasm',desc:'Glucose-alanine cycle (Cahill cycle): Muscle: pyruvate + glutamate → alanine + α-KG (ALT). Alanine exported to blood → liver → pyruvate + glutamate (ALT reverse). Pyruvate → GNG. Glutamate → urea cycle. Safe non-toxic nitrogen transport from muscle. Elevated in fasting.'},
  alpha_keto_acids:{cat:'Cytoplasm',desc:'TCA entry points by AA: Pyruvate — Ala, Cys, Gly, Ser, Thr, Trp (glucogenic). OAA — Asp, Asn (glucogenic). α-KG — Glu, Gln, Pro, Arg, His (glucogenic). Succinyl-CoA — Met, Val, Ile, Thr (glucogenic). Fumarate — Phe, Tyr (both). Acetyl-CoA — Leu, Lys (PURELY KETOGENIC); Ile, Phe, Tyr, Trp, Thr (both). Note: only FAs+ketogenic AAs enter as acetyl-CoA → cannot be net gluconeogenic.'},
  citrate_shuttle:{cat:'Cytoplasm',desc:'Citrate exits mito via citrate transporter when TCA is saturated. In cytoplasm: ATP-citrate lyase → acetyl-CoA + OAA. This is the ONLY way to get mitochondrial acetyl-CoA into cytoplasm for FA synthesis (acetyl-CoA itself cannot cross the inner mito membrane).'},
  acc:{cat:'Cytoplasm',desc:'Acetyl-CoA Carboxylase: rate-limiting enzyme for FA synthesis. Adds CO2 to acetyl-CoA → malonyl-CoA. Requires biotin (B7) + ATP. ✦ Activated by: citrate (allosteric, causes polymerization), insulin (dephosphorylation). ✗ Inhibited by: palmitoyl-CoA (product feedback), AMPK (phosphorylation), glucagon. Product malonyl-CoA also inhibits CPT-1 → prevents simultaneous FA synthesis and β-oxidation.'},
  malonylcoa:{cat:'Cytoplasm',desc:'Two roles: (1) FA elongation substrate for FAS (7 malonyl-CoA + 1 acetyl-CoA → palmitate). (2) INHIBITS CPT-1 — when malonyl-CoA is high (FA synthesis on), CPT-1 is blocked → no FA entry into mito → no β-oxidation. KEY SWITCH preventing futile cycling: insulin↑ → ACC↑ → malonyl-CoA↑ → CPT-1↓.'},
  fas:{cat:'Cytoplasm',desc:'Fatty Acid Synthase: multifunctional enzyme complex. Each elongation cycle: malonyl-CoA + acetyl-CoA or acyl-CoA → CO2 loss → ketoacyl-ACP → reduction (NADPH) → dehydration → reduction (NADPH) → saturated acyl-ACP. 7 cycles → palmitate (16C). Needs: 14 NADPH (mainly from PPP+malic enzyme).'},
  palmitate:{cat:'Cytoplasm',desc:'16-carbon saturated FA from FAS. Can be: elongated (→18C stearate), desaturated (palmitoleate, oleate), esterified to TG (storage), esterified to phospholipids (membranes), packaged in VLDL (liver export). Palmitoyl-CoA feedback inhibits ACC.'},
  fattyacylcoa_cyto:{cat:'Cytoplasm',desc:'FA activated by acyl-CoA synthetase (cytoplasm): FA + CoA + ATP → fatty acyl-CoA + AMP + PPi (costs 2 ATP equivalents). This traps FA in cell and makes it reactive. Substrate for: β-oxidation (via CPT-1), TG synthesis, phospholipids. Palmitoyl-CoA feedback-inhibits ACC.'},
  cpt1:{cat:'Cytoplasm',desc:'Carnitine Palmitoyltransferase I (outer mito membrane). RATE-LIMITING step of β-oxidation. Transfers acyl group from CoA to carnitine → acyl-carnitine (crosses inner mito membrane via CACT transporter). ✗ INHIBITED by malonyl-CoA — master switch: FA synthesis on = β-oxidation off. CPT-1 is also activated by AMPK (indirectly via ↓ACC → ↓malonyl-CoA).'},
  pyruvate_mito:{cat:'Mitochondria',desc:'Pyruvate transported from cytoplasm → mitochondrial matrix via MPC (mitochondrial pyruvate carrier; inhibited by UK5099 experimentally). In matrix: PDH (aerobic) or pyruvate carboxylase (when acetyl-CoA high → GNG).'},
  pdh:{cat:'Mitochondria',desc:'Pyruvate Dehydrogenase Complex. Irreversible — commits carbon to TCA. Cofactors: B1 (TPP/thiamine), B2 (FAD), B3 (NAD+), B5 (CoA), lipoic acid. Products: acetyl-CoA + NADH + CO2. ✗ Inhibited by: acetyl-CoA, NADH, ATP (products). ✦ Activated by: AMP, CoA, NAD+, Ca²⁺ (exercise). PDH kinase (phosphorylates=inactivates); PDH phosphatase (activates). PDH deficiency → lactic acidosis, elevated pyruvate, neurological dysfunction.'},
  acetylcoa_mito:{cat:'Mitochondria',desc:'CENTRAL HUB of aerobic metabolism. Sources: PDH (pyruvate), β-oxidation (FAs), ketogenic AAs, ketone utilization (not liver). Fates: TCA cycle (condensing with OAA → citrate), ketogenesis (liver: 2×AcCoA → HMG-CoA → ketones), cholesterol synthesis (cytoplasm via shuttle). CANNOT go back to pyruvate → FAs and purely ketogenic AAs are NOT net gluconeogenic.'},
  oaa_mito:{cat:'Mitochondria',desc:'OAA in mito: condensed with AcCoA by citrate synthase → citrate (TCA entry). Also: malate DH → regenerated at end of TCA (malate→OAA+NADH). Transaminated → aspartate (urea cycle N donor). Low OAA → TCA stalls. Anaplerosis (replenishing OAA/TCA intermediates) is essential.'},
  citrate_synth:{cat:'Mitochondria',desc:'Citrate Synthase: first TCA enzyme. OAA + acetyl-CoA → citrate + CoA. ✗ Inhibited by: ATP, NADH, citrate (product). Controls TCA input rate. Activated by ADP, Ca²⁺. If OAA is low (mito), this step is limiting.'},
  citrate_mito:{cat:'Mitochondria',desc:'First TCA intermediate. Two fates: (1) Aconitase → isocitrate (TCA continues); (2) Exits mito via citrate transporter → cytoplasm → FA synthesis (citrate shuttle) + regulatory signal (inhibits PFK-1, activates ACC/FBPase-1).'},
  isocitrate:{cat:'Mitochondria',desc:'From citrate via aconitase (iron-sulfur enzyme). Substrate for isocitrate DH — rate-limiting TCA enzyme. IDH1 (cytoplasmic) and IDH2 (mitochondrial) mutations produce 2-hydroxyglutarate (oncometabolite) in glioma, AML.'},
  idh:{cat:'Mitochondria',desc:'Isocitrate Dehydrogenase: RATE-LIMITING of TCA. Isocitrate → α-KG + NADH + CO2. ✗ Inhibited by: ATP, NADH. ✦ Activated by: ADP, Ca²⁺ (matches TCA to energy need and muscle contraction). IDH mutations are oncogenic in glioma and AML.'},
  akg:{cat:'Mitochondria',desc:'α-Ketoglutarate (= 2-oxoglutarate). Central node connecting TCA and AA metabolism. TCA: from isocitrate (IDH). AA catabolism: from glutamate (GDH), glutamine, proline, arginine, histidine (transamination). Feeds akgDH → succinyl-CoA.'},
  akgdh:{cat:'Mitochondria',desc:'α-KG Dehydrogenase Complex. Like PDH: requires B1/thiamine (TPP), lipoic acid, FAD, NAD+. α-KG → succinyl-CoA + NADH + CO2. ✗ Inhibited by: succinyl-CoA (product), NADH. Not regulated by phosphorylation (unlike PDH).'},
  succinylcoa:{cat:'Mitochondria',desc:'High-energy thioester. → succinate + GTP (substrate-level phosphorylation via succinyl-CoA synthetase — only TCA step producing GTP). Entry for: Met, Val, Ile, Thr (glucogenic AAs), odd-chain FAs (propionyl-CoA → methylmalonyl-CoA → succinyl-CoA; requires B12 + biotin). Also: heme synthesis (ALA synthase uses succinyl-CoA + Gly).'},
  succinate:{cat:'Mitochondria',desc:'Oxidized by succinate DH (SDH = Complex II of ETC). Dual role: TCA + ETC. Complex II: transfers e- to FADH2 → CoQ. Inhibited by malonate (competitive, classic inhibitor used in biochemistry). SDH mutations → hereditary paraganglioma/pheochromocytoma.'},
  fumarate_mito:{cat:'Mitochondria',desc:'From Complex II/SDH. Also enters from urea cycle (argininosuccinate → arginine + fumarate) → links urea cycle to TCA. From Phe/Tyr catabolism. Fumarase (fumarate hydratase) → malate. Fumarase mutations → fumaric aciduria + cancer.'},
  malate:{cat:'Mitochondria',desc:'From fumarase. Malate DH: malate + NAD+ → OAA + NADH (closes TCA). Malate can exit mito via malate-aspartate shuttle (brings NADH reducing equivalents from cytoplasm to mito for ETC). Also: malic enzyme: malate → pyruvate + NADPH (cytoplasm) — another source of NADPH.'},
  hmgcoa:{cat:'Mitochondria',desc:'HMG-CoA in MITOCHONDRIA (different pool from cytoplasmic HMG-CoA for cholesterol synthesis). 2 AcCoA → acetoacetyl-CoA → + AcCoA → HMG-CoA (HMG-CoA synthase, liver). Rate-limiting for ketogenesis. HMG-CoA lyase → acetoacetate + AcCoA. Rate increases with high fat diet, starvation, uncontrolled T1DM.'},
  ketones:{cat:'Mitochondria',desc:'Ketone bodies: acetoacetate + β-hydroxybutyrate (β-OHB, reduced by β-OHB-DH + NADH) + acetone (spontaneous decarboxylation). Made in LIVER mito. Used by: brain, heart, kidney, muscle. LIVER CANNOT USE KETONES (lacks thiophorase/succinyl-CoA:3-ketoacid-CoA transferase). DKA: uncontrolled T1DM → excess FFA → excess acetyl-CoA → ketogenesis overwhelms buffering → pH↓.'},
  fattyacylcoa_mito:{cat:'Mitochondria',desc:'Fatty acyl-CoA in mito matrix. From CPT-1/CACT/CPT-2 transport system. Undergoes β-oxidation: (1) Acyl-CoA DH (FAD→FADH2) → trans-enoyl-CoA; (2) Enoyl-CoA hydratase (+H2O) → 3-hydroxyacyl-CoA; (3) 3-hydroxyacyl-CoA DH (NAD+→NADH); (4) Thiolase (+CoA, thiolysis) → acetyl-CoA + shortened acyl-CoA.'},
  beta_ox:{cat:'Mitochondria',desc:'β-Oxidation spiral. Each turn: −2C as acetyl-CoA, +1 FADH2 + 1 NADH. Palmitate (16C): 7 turns → 8 acetyl-CoA + 7 FADH2 + 7 NADH → ~106 ATP net. Odd-chain FAs: last product = propionyl-CoA → propionyl-CoA carboxylase (biotin) → methylmalonyl-CoA → succinyl-CoA (B12, methylmalonyl-CoA mutase). β-oxidation is suppressed when malonyl-CoA is high.'},
  complex1:{cat:'ETC',desc:'Complex I (NADH Dehydrogenase). NADH → NAD+ (e- to CoQ). Pumps 4H+/pair across inner mito membrane. Contains FMN and Fe-S centers. ✗ Inhibited by: rotenone (insecticide), amytal, MPTP (dopaminergic neurotoxin → parkinsonism). Produces ~2.5 ATP per NADH.'},
  complex2:{cat:'ETC',desc:'Complex II (Succinate DH). FADH2 → FAD (e- to CoQ). Does NOT pump H+ → less ATP per FADH2 (~1.5 ATP). Only ETC complex that is also a TCA enzyme. Contains FAD + Fe-S. Inhibited by malonate (competitive with succinate). SDH mutations → SDHA/B/C/D → hereditary paraganglioma/pheochromocytoma.'},
  complex3:{cat:'ETC',desc:'Complex III (Cytochrome bc1). CoQH2 → cytochrome c. Pumps 4H+ (Q-cycle mechanism). Contains: cytochrome b (ubiquinol binding), Rieske Fe-S, cytochrome c1. ✗ Inhibited by: antimycin A (blocks Qi site).'},
  complex4:{cat:'ETC',desc:'Complex IV (Cytochrome c Oxidase). Cyt c → O2 → 2H2O. Final e- acceptor. Pumps 2H+/pair. Contains: Cu_A, heme a, heme a3-Cu_B. ✗ Inhibited by: CN- (cyanide), CO, azide, H2S — all block O2 binding → ETC halts → no ATP → cellular asphyxiation. Rate-limiting step under normal physiological conditions.'},
  atp_synthase:{cat:'ETC',desc:'ATP Synthase (Complex V / F0F1-ATPase). H+ flows down gradient through F0 → rotates γ-subunit → F1 catalytic head changes conformation → ADP+Pi → ATP. ~2.5 ATP per NADH, ~1.5 ATP per FADH2. ✗ Inhibited by: oligomycin (blocks F0 H+ channel → H+ cannot flow → gradient builds → upstream ETC slows). Uncouplers (DNP, thermogenin/UCP-1 in brown fat) dissipate gradient as HEAT without making ATP.'},
  proton_gradient:{cat:'ETC',desc:'Electrochemical H+ gradient (proton-motive force) across inner mito membrane. Generated by Complexes I, III, IV pumping H+ into intermembrane space. Used by ATP synthase. Uncouplers (DNP, thermogenin) collapse gradient → heat, not ATP. Brown adipose: UCP-1 → thermogenesis (newborns, hibernators).'},
  atp_out:{cat:'ETC',desc:'Total ATP per glucose: ~30-32 ATP (modern mitochondrial coupling ratio estimates). Substrate-level: 2 (glycolysis) + 2 (TCA) = 4 ATP. Oxidative: 10 NADH × 2.5 = 25 + 2 FADH2 × 1.5 = 3 ATP. Total ~32 ATP. Old textbook number (38 ATP) overestimates due to membrane leakage and ATP/ADP transport costs.'},
  nh4_plus:{cat:'Urea Cycle',desc:'NH4+ from: GDH (glutamate → α-KG + NH4+), glutaminase, AMP deaminase. Toxic: disrupts TCA (depletes α-KG → OAA), inhibits PDH, causes cerebral edema. Must be detoxified in liver (urea cycle) or kidney (→ NH4+ in urine for acid-base). Hyperammonemia: liver failure, urea cycle defects → encephalopathy.'},
  nag:{cat:'Urea Cycle',desc:'N-Acetylglutamate: obligate allosteric activator of CPS-I (without NAG, CPS-I is completely inactive). Made by NAG synthase: acetyl-CoA + glutamate → NAG. High protein/AA → ↑ glutamate → ↑ NAG → ↑ CPS-I → ↑ urea cycle. This couples protein catabolism rate directly to urea disposal capacity.'},
  cpsi:{cat:'Urea Cycle',desc:'CPS-I (Carbamoyl Phosphate Synthetase I): first committed step, mitochondrial. NH4+ + CO2 + 2ATP → carbamoyl phosphate. Activated ONLY by NAG. CPS-I deficiency: hyperammonemia type I. CPSII (cytoplasmic, different enzyme): uses glutamine, makes carbamoyl-P for pyrimidine synthesis.'},
  carbamoyl_p:{cat:'Urea Cycle',desc:'Carbamoyl phosphate (mito). Condensed with ornithine by OTC (ornithine transcarbamylase) → citrulline. OTC deficiency: most common urea cycle disorder, X-linked (males affected; females carriers with variable expression). Presents with hyperammonemia especially post-high-protein meal.'},
  ornithine:{cat:'Urea Cycle',desc:'Recycled carrier. Imported from cytoplasm into mito (via ornithine/citrulline antiporter). Condenses with carbamoyl phosphate → citrulline (mito). Regenerated from arginine by arginase (last step, cytoplasm). Ornithine is the structural backbone that gets passed around the cycle.'},
  citrulline:{cat:'Urea Cycle',desc:'Exits mito to cytoplasm via citrulline/ornithine antiporter. Condensed with aspartate (argininosuccinate synthetase, +ATP → AMP+PPi) → argininosuccinate. Citrullinemia: argininosuccinate synthetase deficiency.'},
  aspartate_uc:{cat:'Urea Cycle',desc:'Second nitrogen for urea (from aspartate, not NH4+ directly). OAA → aspartate via transamination (glutamate as N donor). This is the biochemical bridge: TCA → OAA → aspartate → urea cycle N. Argininosuccinate synthetase deficiency → citrullinemia.'},
  argininosuccinate:{cat:'Urea Cycle',desc:'Argininosuccinate lyase cleaves → arginine + fumarate. Fumarate enters TCA (fumarate → malate → OAA). LINK BETWEEN UREA CYCLE AND TCA CYCLE. Argininosuccinic aciduria: ASL deficiency → argininosuccinate accumulation.'},
  arginine_uc:{cat:'Urea Cycle',desc:'Arginase (liver cytoplasm): arginine → ornithine + urea. Ornithine → mito (recycled). Urea → blood → kidney → urine. Arginine is conditionally essential (adults can synthesize via urea cycle intermediates). Arginase deficiency: hyperammonemia type II.'},
  urea_out:{cat:'Urea Cycle',desc:'Urea: 2 nitrogens (1 from NH4+, 1 from aspartate). Non-toxic. Excreted in urine. Net cost: 4 ATP per urea. BUN (blood urea nitrogen): clinical marker. ↑ BUN: ↑ protein catabolism, dehydration, GI bleed (blood protein digested), pre-renal failure. ↓ BUN: liver failure (cannot make urea), malnutrition.'},
  fumarate_uc:{cat:'Urea Cycle',desc:'Fumarate byproduct of argininosuccinate lyase. Enters TCA: fumarate → malate → OAA → can be used for more aspartate (→ urea cycle) or condense with acetyl-CoA (→ citrate). This creates the urea cycle-TCA CYCLE LINK — nitrogen disposal is energetically coupled to central metabolism.'},
};

